const { createClient } = require('@supabase/supabase-js');
const XLSX = require('xlsx');
const fs = require('fs');

const supabase = createClient(
  'https://ebktoazswvtqsjrjryqk.supabase.co',
  'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImVia3RvYXpzd3Z0cXNqcmpyeXFrIiwicm9sZSI6ImFub24iLCJpYXQiOjE3NzM5MDM2NzIsImV4cCI6MjA4OTQ3OTY3Mn0.a3kFa8JOBlvZ-PSMWEcIDQKLLPDrXbPf4qTRptWvki8'
);

async function uploadReturns() {
  const filePath = '/Users/jooho/Downloads/교환_반품 데이터 2025.11. ~ (24).xlsx';

  console.log('엑셀 파일 읽는 중...');
  const workbook = XLSX.readFile(filePath);
  const sheetName = workbook.SheetNames[0];
  const data = XLSX.utils.sheet_to_json(workbook.Sheets[sheetName], { header: 1 });

  // 헤더는 4번째 행 (인덱스 3)
  const headers = data[3];
  const rows = data.slice(4);

  console.log(`총 ${rows.length}개 행 발견`);

  // 기존 데이터 확인
  const { data: existing, error: fetchError } = await supabase
    .from('returns')
    .select('return_date, order_number')
    .order('return_date', { ascending: false })
    .limit(1);

  if (fetchError) {
    console.error('기존 데이터 조회 오류:', fetchError);
    // 테이블이 없을 수 있으므로 계속 진행
  } else if (existing && existing.length > 0) {
    console.log(`데이터베이스 최신 데이터: ${existing[0].return_date} | ${existing[0].order_number}`);
  } else {
    console.log('데이터베이스에 기존 데이터 없음');
  }

  // 데이터 파싱 및 변환
  const records = [];
  let newCount = 0;

  for (const row of rows) {
    // 빈 행 건너뛰기
    if (!row[0] && !row[1] && !row[2]) continue;

    const year = row[0];
    const month = row[1];
    const day = row[2];

    if (!year || !month || !day) continue;

    const returnDate = `${year}-${String(month).padStart(2, '0')}-${String(day).padStart(2, '0')}`;

    // 2026년 6월 4일까지만
    if (returnDate > '2026-06-04') continue;

    const record = {
      return_date: returnDate,
      year: parseInt(year),
      month: parseInt(month),
      day: parseInt(day),
      channel: row[3] || null,
      return_type: row[4] || null,
      barcode: row[5] ? String(row[5]) : null,
      customer_name: row[6] || null,
      original_tracking: row[7] ? String(row[7]) : null,
      return_tracking: row[8] ? String(row[8]) : null,
      order_number: row[9] ? String(row[9]) : null,
      reason: row[10] || null,
      category: row[11] || null,
      product_name: row[12] || null,
      quantity: row[13] ? parseInt(row[13]) : 1,
      defect_level: row[14] || null,
      internal_note: row[15] || null,
      customer_voc: row[16] || null,
      receipt_issued: row[17] === true || row[17] === 'TRUE' || row[17] === 'True',
      amount: row[18] ? parseFloat(row[18]) : null,
      note: row[19] || null,
      receipt_delivered: row[20] === true || row[20] === 'TRUE' || row[20] === 'True',
      receipt_content: row[21] || null,
      created_by: 'system_excel'
    };

    records.push(record);
    newCount++;
  }

  console.log(`\n업로드할 데이터: ${records.length}건`);
  console.log(`날짜 범위: ${records[0].return_date} ~ ${records[records.length - 1].return_date}`);

  if (records.length === 0) {
    console.log('업로드할 새 데이터가 없습니다.');
    return;
  }

  // 배치로 업로드 (1000개씩)
  const batchSize = 1000;
  let uploaded = 0;

  for (let i = 0; i < records.length; i += batchSize) {
    const batch = records.slice(i, i + batchSize);
    const { error } = await supabase
      .from('returns')
      .insert(batch);

    if (error) {
      console.error(`배치 ${Math.floor(i / batchSize) + 1} 업로드 오류:`, error);
      break;
    }

    uploaded += batch.length;
    console.log(`${uploaded}/${records.length} 업로드 완료...`);
  }

  console.log(`\n✅ 총 ${uploaded}건 업로드 완료!`);

  // 업로드 후 확인
  const { data: final, count } = await supabase
    .from('returns')
    .select('*', { count: 'exact' })
    .gte('return_date', '2026-06-01')
    .lte('return_date', '2026-06-04');

  console.log(`\n2026년 6월 1~4일 최종 데이터: ${count}건`);
}

uploadReturns().catch(console.error);

