const XLSX = require('xlsx')
const { createClient } = require('@supabase/supabase-js')
require('dotenv').config({ path: '.env.local' })

// Supabase 클라이언트 생성
const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL
const supabaseKey = process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY

if (!supabaseUrl || !supabaseKey) {
  console.error('Supabase 환경 변수가 설정되지 않았습니다.')
  process.exit(1)
}

const supabase = createClient(supabaseUrl, supabaseKey)

// 엑셀 파일 읽기
const filePath = '/Users/jooho/Downloads/교환_반품 데이터 2025.11. ~ (22).xlsx'

console.log('📂 파일 읽기 시작:', filePath)

const workbook = XLSX.readFile(filePath)
const sheetName = workbook.SheetNames[0]
const worksheet = workbook.Sheets[sheetName]

// JSON으로 변환
const rawData = XLSX.utils.sheet_to_json(worksheet, { header: 1 })

console.log(`✅ 총 ${rawData.length}행 읽기 완료\n`)

// 헤더는 3번 행(인덱스 3), 데이터는 4번 행(인덱스 4)부터 시작
const dataRows = rawData.slice(4).filter(row => row && row[0]) // 빈 행 제외

console.log(`📊 변환할 데이터: ${dataRows.length}건\n`)

// 데이터 변환
const transformedData = dataRows.map((row, idx) => {
  return {
    year: row[0] || new Date().getFullYear(),
    month: row[1] || 1,
    day: row[2] || 1,
    distributor: row[3] || '',
    type: row[4] || '반품',
    payment_method: row[5] || '',
    recipient: row[6] || '',
    original_tracking: row[7] ? String(row[7]) : '',
    return_tracking: row[8] ? String(row[8]) : '',
    order_no: row[9] ? String(row[9]) : '',
    reason: row[10] || '',
    category: row[11] || '',
    product_name: row[12] || '',
    quantity: row[13] || 1,
    defect_level: row[14] === '경결함' ? '경결함' : '미결함',
    internal_notes: row[15] || '',
    customer_voc: row[16] || '',
    cash_receipt_issued: row[17] === true || row[17] === 'true' || row[17] === 'TRUE',
    amount: row[18] ? String(row[18]) : '',
    notes: row[19] || '',
    receipt_delivered: row[20] === true || row[20] === 'true' || row[20] === 'TRUE',
    receipt_details: row[21] || '',
    barcode: '' // 바코드는 별도로 매핑 필요
  }
})

console.log('📝 샘플 데이터 (첫 3건):')
console.log(JSON.stringify(transformedData.slice(0, 3), null, 2))

// Supabase에 업로드
async function uploadData() {
  console.log('\n🚀 Supabase 업로드 시작...\n')

  // 기존 데이터 삭제 여부 확인
  console.log('⚠️  기존 데이터를 모두 삭제하고 새로 업로드합니다.')

  // 기존 데이터 삭제
  const { error: deleteError } = await supabase
    .from('return_exchange_data')
    .delete()
    .neq('id', 0) // 모든 데이터 삭제

  if (deleteError) {
    console.error('❌ 기존 데이터 삭제 실패:', deleteError)
    process.exit(1)
  }

  console.log('✅ 기존 데이터 삭제 완료\n')

  // 100개씩 나눠서 업로드
  const batchSize = 100
  let successCount = 0
  let errorCount = 0

  for (let i = 0; i < transformedData.length; i += batchSize) {
    const batch = transformedData.slice(i, i + batchSize)

    const { data, error } = await supabase
      .from('return_exchange_data')
      .insert(batch)

    if (error) {
      console.error(`❌ 배치 ${Math.floor(i / batchSize) + 1} 업로드 실패:`, error.message)
      errorCount += batch.length
    } else {
      successCount += batch.length
      console.log(`✅ 배치 ${Math.floor(i / batchSize) + 1} 업로드 완료 (${successCount}/${transformedData.length})`)
    }
  }

  console.log('\n📊 업로드 결과:')
  console.log(`   성공: ${successCount}건`)
  console.log(`   실패: ${errorCount}건`)
  console.log(`   총계: ${transformedData.length}건\n`)

  if (errorCount === 0) {
    console.log('🎉 모든 데이터 업로드 완료!')
  }
}

uploadData().catch(console.error)

