import { supabase } from '@/lib/supabase'
import SalesDashboard from '@/components/SalesDashboard'

export const dynamic = 'force-dynamic'
export const revalidate = 0

export default async function SalesDashboardPage() {
  // 기본 기간: 2026년 1월부터 현재까지
  const startDate = '2026-01-01'
  const endDate = new Date().toISOString().split('T')[0]

  // 기간별 판매량 데이터 (월별로 나눠서 조회)
  const allSalesData = []
  const allOrdersData = []

  const currentMonth = new Date().getMonth() + 1 // 1-12

  for (let month = 1; month <= currentMonth; month++) {
    const monthStr = `2026-${String(month).padStart(2, '0')}`
    const lastDay = new Date(2026, month, 0).getDate()
    const monthStart = `${monthStr}-01`
    const monthEnd = `${monthStr}-${String(lastDay).padStart(2, '0')}`

    // 판매 데이터 (pagination)
    let salesOffset = 0
    const limit = 1000

    while (true) {
      const { data: monthSales } = await supabase
        .from('daily_sales')
        .select(`
          *,
          product_barcodes (
            product_name,
            category,
            color,
            size
          )
        `)
        .gte('sale_date', monthStart)
        .lte('sale_date', monthEnd)
        .order('sale_date', { ascending: true })
        .range(salesOffset, salesOffset + limit - 1)

      if (!monthSales || monthSales.length === 0) break

      allSalesData.push(...monthSales)

      if (monthSales.length < limit) break
      salesOffset += limit
    }

    // 택배건수 데이터 (pagination)
    let ordersOffset = 0

    while (true) {
      const { data: monthOrders } = await supabase
        .from('sales_orders')
        .select('order_date, warehouse, barcode')
        .gte('order_date', monthStart)
        .lte('order_date', monthEnd)
        .range(ordersOffset, ordersOffset + limit - 1)

      if (!monthOrders || monthOrders.length === 0) break

      allOrdersData.push(...monthOrders)

      if (monthOrders.length < limit) break
      ordersOffset += limit
    }
  }

  const salesData = allSalesData
  const ordersData = allOrdersData

  // 카테고리별 합계
  const categoryTotalsMap = salesData?.reduce((acc, sale) => {
    const category = sale.product_barcodes?.category || '기타'
    if (!acc[category]) acc[category] = 0
    acc[category] += parseFloat(sale.quantity)
    return acc
  }, {} as Record<string, number>)

  const categoryTotals = Object.entries(categoryTotalsMap || {}).map(([category, total]) => ({
    category,
    total: total as number
  }))

  // SKU별 순위 (상위 20개)
  const salesByProduct = salesData?.reduce((acc, sale) => {
    const key = sale.product_barcode
    if (!acc[key]) {
      acc[key] = {
        barcode: key,
        product_name: sale.product_barcodes?.product_name || key,
        category: sale.product_barcodes?.category || '기타',
        total_quantity: 0
      }
    }
    acc[key].total_quantity += parseFloat(sale.quantity)
    return acc
  }, {} as Record<string, any>)

  const topProducts = (Object.values(salesByProduct || {}) as Array<{
    barcode: string
    product_name: string
    category: string
    total_quantity: number
  }>)
    .sort((a, b) => b.total_quantity - a.total_quantity)
    .slice(0, 20)

  // 일별 데이터 (택배건수 + 판매수량)
  const dailyMap = salesData?.reduce((acc, sale) => {
    const date = sale.sale_date
    if (!acc[date]) {
      acc[date] = { date, quantity: 0, orderCount: 0 }
    }
    acc[date].quantity += parseFloat(sale.quantity)
    return acc
  }, {} as Record<string, any>)

  // 택배건수 추가
  ordersData?.forEach(order => {
    if (dailyMap[order.order_date]) {
      dailyMap[order.order_date].orderCount++
    } else {
      dailyMap[order.order_date] = {
        date: order.order_date,
        quantity: 0,
        orderCount: 1
      }
    }
  })

  interface ChartDataPoint {
    date: string
    quantity: number
    orderCount: number
  }

  const chartData = Object.values(dailyMap || {}).sort((a: any, b: any) =>
    a.date.localeCompare(b.date)
  ) as ChartDataPoint[]

  // 카테고리별 일별 판매수량
  const categoryDailyMap: Record<string, Record<string, number>> = {}
  salesData?.forEach(sale => {
    const category = sale.product_barcodes?.category || '기타'
    const date = sale.sale_date
    if (!categoryDailyMap[category]) categoryDailyMap[category] = {}
    categoryDailyMap[category][date] = (categoryDailyMap[category][date] || 0) + parseFloat(sale.quantity)
  })

  // 모든 날짜 (정렬)
  const allDates = chartData.map(p => p.date)

  // 카테고리별 차트 데이터 (모든 날짜 포함, 없는 날은 0)
  const categoryChartData = Object.entries(categoryDailyMap)
    .map(([category, dateMap]) => ({
      category,
      total: Object.values(dateMap).reduce((s, q) => s + q, 0),
      data: allDates.map(date => ({
        date,
        quantity: dateMap[date] || 0
      }))
    }))
    .sort((a, b) => b.total - a.total)

  // 창고별 집계
  const warehouseStats = {
    dream: {
      orders: ordersData?.filter(o => o.warehouse === '드림산업').length || 0,
      quantity: salesData?.filter(s => s.warehouse === '드림산업').reduce((sum, s) => sum + parseFloat(s.quantity), 0) || 0
    },
    tumin: {
      orders: ordersData?.filter(o => o.warehouse === '투민글로벌').length || 0,
      quantity: salesData?.filter(s => s.warehouse === '투민글로벌').reduce((sum, s) => sum + parseFloat(s.quantity), 0) || 0
    }
  }

  // 통계 요약
  const totalQuantity = salesData?.reduce((sum, sale) => sum + parseFloat(sale.quantity), 0) || 0
  const totalOrders = ordersData?.length || 0
  const daysCount = new Set(salesData?.map(s => s.sale_date)).size
  const avgOrdersPerDay = daysCount > 0 ? (totalOrders / daysCount).toFixed(1) : 0

  // 평균 판매수량 / 건
  const avgQtyPerOrder = totalOrders > 0 ? (totalQuantity / totalOrders).toFixed(1) : '0'

  return (
    <main className="min-h-screen" style={{ background: '#F6F6F2' }}>
      <div className="max-w-[1600px] mx-auto px-8 py-10">
        {/* 페이지 헤더 */}
        <div className="mb-10">
          <div className="flex items-end justify-between">
            <div>
              <h1
                className="text-4xl font-bold tracking-tight mb-3"
                style={{ color: '#181c20' }}
              >
                판매량 대시보드
              </h1>
              <p className="text-sm" style={{ color: '#46474a' }}>
                <span className="font-semibold" style={{ color: '#181c20' }}>{startDate}</span>
                <span className="mx-2" style={{ color: '#74777b' }}>—</span>
                <span className="font-semibold" style={{ color: '#181c20' }}>{endDate}</span>
                <span className="mx-2" style={{ color: '#74777b' }}>·</span>
                <span style={{ color: '#46474a' }}>{daysCount}일간 데이터</span>
              </p>
            </div>
            <div className="hidden md:flex items-center gap-2">
              <span
                className="px-3 py-1.5 rounded-full text-xs font-bold uppercase tracking-wide"
                style={{ background: '#6bfe9c', color: '#00743a' }}
              >
                LIVE
              </span>
              <span className="text-xs" style={{ color: '#74777b' }}>실시간 업데이트</span>
            </div>
          </div>
        </div>

        {/* 통계 요약 카드 - 디자인 시스템 적용 */}
        <div className="grid grid-cols-1 md:grid-cols-4 gap-5 mb-10">
          <div className="rounded-3xl p-7" style={{ background: '#ffffff' }}>
            <div className="flex items-start justify-between mb-4">
              <div className="text-xs font-bold uppercase tracking-wider" style={{ color: '#74777b' }}>
                총 택배건수
              </div>
              <div
                className="w-10 h-10 rounded-2xl flex items-center justify-center"
                style={{ background: 'linear-gradient(135deg, #0058bc 0%, #2571df 100%)' }}
              >
                <svg className="w-5 h-5 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 8h14M5 8a2 2 0 110-4h14a2 2 0 110 4M5 8v10a2 2 0 002 2h10a2 2 0 002-2V8m-9 4h4" />
                </svg>
              </div>
            </div>
            <div
              className="text-4xl font-bold tracking-tight"
              style={{ color: '#181c20' }}
            >
              {totalOrders.toLocaleString()}
            </div>
            <div className="text-xs mt-2" style={{ color: '#74777b' }}>건</div>
          </div>

          <div className="rounded-3xl p-7" style={{ background: '#ffffff' }}>
            <div className="flex items-start justify-between mb-4">
              <div className="text-xs font-bold uppercase tracking-wider" style={{ color: '#74777b' }}>
                총 판매수량
              </div>
              <div
                className="w-10 h-10 rounded-2xl flex items-center justify-center"
                style={{ background: 'linear-gradient(135deg, #006d37 0%, #00a651 100%)' }}
              >
                <svg className="w-5 h-5 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M20 7l-8-4-8 4m16 0l-8 4m8-4v10l-8 4m0-10L4 7m8 4v10M4 7v10l8 4" />
                </svg>
              </div>
            </div>
            <div
              className="text-4xl font-bold tracking-tight"
              style={{ color: '#181c20' }}
            >
              {totalQuantity.toLocaleString()}
            </div>
            <div className="text-xs mt-2" style={{ color: '#74777b' }}>개</div>
          </div>

          <div className="rounded-3xl p-7" style={{ background: '#ffffff' }}>
            <div className="flex items-start justify-between mb-4">
              <div className="text-xs font-bold uppercase tracking-wider" style={{ color: '#74777b' }}>
                일평균 택배
              </div>
              <div
                className="w-10 h-10 rounded-2xl flex items-center justify-center"
                style={{ background: 'linear-gradient(135deg, #d97706 0%, #f59e0b 100%)' }}
              >
                <svg className="w-5 h-5 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 7h8m0 0v8m0-8l-8 8-4-4-6 6" />
                </svg>
              </div>
            </div>
            <div
              className="text-4xl font-bold tracking-tight"
              style={{ color: '#181c20' }}
            >
              {avgOrdersPerDay}
            </div>
            <div className="text-xs mt-2" style={{ color: '#74777b' }}>건 / 일</div>
          </div>

          <div className="rounded-3xl p-7" style={{ background: '#ffffff' }}>
            <div className="flex items-start justify-between mb-4">
              <div className="text-xs font-bold uppercase tracking-wider" style={{ color: '#74777b' }}>
                건당 평균 수량
              </div>
              <div
                className="w-10 h-10 rounded-2xl flex items-center justify-center"
                style={{ background: 'linear-gradient(135deg, #6366f1 0%, #8b5cf6 100%)' }}
              >
                <svg className="w-5 h-5 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 19v-6a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2a2 2 0 002-2zm0 0V9a2 2 0 012-2h2a2 2 0 012 2v10m-6 0a2 2 0 002 2h2a2 2 0 002-2m0 0V5a2 2 0 012-2h2a2 2 0 012 2v14a2 2 0 01-2 2h-2a2 2 0 01-2-2z" />
                </svg>
              </div>
            </div>
            <div
              className="text-4xl font-bold tracking-tight"
              style={{ color: '#181c20' }}
            >
              {avgQtyPerOrder}
            </div>
            <div className="text-xs mt-2" style={{ color: '#74777b' }}>개 / 건</div>
          </div>
        </div>

        {/* 대시보드 컴포넌트 */}
        <SalesDashboard
          chartData={chartData}
          topProducts={topProducts}
          categoryTotals={categoryTotals || []}
          categoryChartData={categoryChartData}
          warehouseStats={warehouseStats}
          startDate={startDate}
          endDate={endDate}
        />
      </div>
    </main>
  )
}

'use client'

import { useState } from 'react'

interface ChartDataPoint {
  date: string
  quantity: number
  orderCount: number
}

interface TopProduct {
  barcode: string
  product_name: string
  category: string
  total_quantity: number
}

interface CategoryTotal {
  category: string
  total: number
}

interface CategoryChartItem {
  category: string
  total: number
  data: { date: string; quantity: number }[]
}

interface WarehouseStats {
  dream: { orders: number; quantity: number }
  tumin: { orders: number; quantity: number }
}

interface Props {
  chartData: ChartDataPoint[]
  topProducts: TopProduct[]
  categoryTotals: CategoryTotal[]
  categoryChartData?: CategoryChartItem[]
  warehouseStats: WarehouseStats
  startDate: string
  endDate: string
}

const TABS = [
  { key: 'chart', label: '일별 추이', icon: '📈' },
  { key: 'warehouse', label: '창고별', icon: '🏢' },
  { key: 'categories', label: '카테고리', icon: '📦' },
  { key: 'products', label: 'Top 20', icon: '🏆' },
] as const

type TabKey = typeof TABS[number]['key']

export default function SalesDashboard({ chartData, topProducts, categoryTotals, categoryChartData = [], warehouseStats, startDate, endDate }: Props) {
  const [selectedTab, setSelectedTab] = useState<TabKey>('chart')
  const [hoveredPoint, setHoveredPoint] = useState<{ chart: string; idx: number } | null>(null)

  const totalDreamQty = warehouseStats.dream.quantity
  const totalTuminQty = warehouseStats.tumin.quantity
  const totalQty = totalDreamQty + totalTuminQty
  const dreamPercent = totalQty > 0 ? (totalDreamQty / totalQty) * 100 : 0
  const tuminPercent = totalQty > 0 ? (totalTuminQty / totalQty) * 100 : 0

  return (
    <div className="space-y-6">
      {/* 탭 메뉴 - pill 스타일 */}
      <div
        className="inline-flex flex-wrap gap-1 p-2 rounded-2xl"
        style={{ background: '#ebeef4' }}
      >
        {TABS.map((tab) => (
          <button
            key={tab.key}
            onClick={() => setSelectedTab(tab.key)}
