                              left: `${((hoveredPoint.idx + 0.5) / cat.data.length) * 100}%`,
                              top: '5px', transform: 'translateX(-50%)',
                              boxShadow: '0px 12px 32px rgba(24, 28, 32, 0.2)', whiteSpace: 'nowrap'
                            }}
                          >
                            <div className="font-bold mb-1">{cat.data[hoveredPoint.idx].date}</div>
                            <div>판매: <span className="font-bold">{cat.data[hoveredPoint.idx].quantity}개</span></div>
                          </div>
                        )}
                      </div>
                      {/* x축 날짜 라벨 */}
                      <div className="relative mt-3" style={{ height: '16px' }}>
                        {cat.data.map((p, i) => {
                          const step = Math.max(1, Math.floor(cat.data.length / 10))
                          if (i % step !== 0 && i !== cat.data.length - 1) return null
                          const left = ((i + 0.5) / cat.data.length) * 100
                          return (
                            <span
                              key={i}
                              className="absolute text-[10px] font-medium whitespace-nowrap"
                              style={{ left: `${left}%`, transform: 'translateX(-50%)', color: c.primary, opacity: 0.7 }}
                            >
                              {p.date.substring(5).replace('-', '/')}
                            </span>
                          )
                        })}
                      </div>
                    </div>
                  </div>
                </div>
              )
            })
          ) : (
            <div className="rounded-3xl p-20 text-center" style={{ background: '#ffffff', color: '#74777b' }}>
              <div className="text-5xl mb-3">📦</div>
              <p className="text-sm">카테고리 데이터가 없습니다</p>
            </div>
          )}
        </div>
      )}

      {/* Top 20 */}
      {selectedTab === 'products' && (
        <div className="rounded-3xl overflow-hidden" style={{ background: '#ffffff' }}>
          <div className="px-8 py-6">
            <h3
              className="text-2xl font-bold tracking-tight"
              style={{ color: '#181c20' }}
            >
              판매량 Top 20
            </h3>
            <p className="text-sm mt-1" style={{ color: '#74777b' }}>
              가장 많이 팔린 제품 순위
            </p>
          </div>

          <div className="px-2 pb-2">
            <table className="w-full">
              <thead>
                <tr style={{ background: '#f1f4fa' }}>
                  <th className="px-6 py-4 text-center text-xs font-bold uppercase tracking-wider rounded-tl-2xl" style={{ color: '#46474a', width: '70px' }}>순위</th>
                  <th className="px-6 py-4 text-left text-xs font-bold uppercase tracking-wider" style={{ color: '#46474a' }}>카테고리</th>
                  <th className="px-6 py-4 text-left text-xs font-bold uppercase tracking-wider" style={{ color: '#46474a' }}>상품명</th>
                  <th className="px-6 py-4 text-left text-xs font-bold uppercase tracking-wider" style={{ color: '#46474a' }}>바코드</th>
                  <th className="px-6 py-4 text-right text-xs font-bold uppercase tracking-wider rounded-tr-2xl" style={{ color: '#46474a' }}>판매량</th>
                </tr>
              </thead>
              <tbody>
                {topProducts.map((product, index) => {
                  const isTop3 = index < 3
                  return (
                    <tr
                      key={product.barcode}
                      className="transition-colors hover:bg-blue-50/50"
                      style={{ background: index % 2 === 0 ? '#ffffff' : '#fafbfd' }}
                    >
                      <td className="px-6 py-4 text-center">
                        <div
                          className="w-9 h-9 rounded-full flex items-center justify-center font-bold text-sm mx-auto"
                          style={
                            isTop3
                              ? {
                                  background: index === 0
                                    ? 'linear-gradient(135deg, #d97706 0%, #f59e0b 100%)'
                                    : index === 1
                                    ? 'linear-gradient(135deg, #6b7280 0%, #9ca3af 100%)'
                                    : 'linear-gradient(135deg, #92400e 0%, #b45309 100%)',
                                  color: '#ffffff'
                                }
                              : { background: '#ebeef4', color: '#46474a' }
                          }
                        >
                          {index + 1}
                        </div>
                      </td>
                      <td className="px-6 py-4">
                        <span
                          className="px-2.5 py-1 rounded-full text-xs font-bold uppercase tracking-wide"
                          style={{ background: '#dbeafe', color: '#0058bc' }}
                        >
                          {product.category}
                        </span>
                      </td>
                      <td className="px-6 py-4">
                        <div className="text-sm font-semibold" style={{ color: '#181c20' }}>
                          {product.product_name}
                        </div>
                      </td>
                      <td className="px-6 py-4">
                        <div className="text-xs font-mono" style={{ color: '#74777b' }}>
                          {product.barcode}
                        </div>
                      </td>
                      <td className="px-6 py-4 text-right">
                        <div
                          className="text-xl font-bold tracking-tight"
                          style={{ color: '#181c20' }}
                        >
                          {product.total_quantity.toLocaleString()}
                          <span className="text-xs font-normal ml-1" style={{ color: '#74777b' }}>개</span>
                        </div>
                      </td>
                    </tr>
                  )
                })}
              </tbody>
            </table>

            {topProducts.length === 0 && (
              <div className="text-center py-20" style={{ color: '#74777b' }}>
