const barcodeGroups = ordersData?.reduce((acc, order) => {
  const barcode = order.barcode
  if (!barcode) return acc
  if (!acc[barcode]) acc[barcode] = []
  acc[barcode].push(order)
  return acc
}, {} as Record<string, any[]>)

const multiShipments = Object.values(barcodeGroups || {}).filter(group => group.length > 1).length
const totalShipments = Object.keys(barcodeGroups || {}).length
const multiShipmentRate = totalShipments > 0 ? (multiShipments / totalShipments) * 100 : 0

// 창고별 집계
const warehouseStats = {
  dream: {
    orders: ordersData?.filter(o => o.warehouse === '드림산업').length || 0,
    quantity: salesData?.filter(s => s.warehouse === '드림산업').reduce((sum, s) => sum + parseFloat(s.quantity), 0) || 0
  },
  tumin: {
    orders: ordersData?.filter(o => o.warehouse === '투민글로벌').length || 0,
    quantity: salesData?.filter(s => s.warehouse === '투민글로벌').reduce((sum, s) => sum + parseFloat(s.quantity), 0) || 0
  }
}

// 주차별 집계 (목요일~수요일 기준)
const getWeekNumber = (dateStr: string) => {
  const date = new Date(dateStr)
  const day = date.getDay() // 0=일요일, 1=월요일, ..., 6=토요일
  const adjustedDate = new Date(date)
  adjustedDate.setDate(date.getDate() - ((day + 3) % 7)) // 목요일 기준으로 조정
  const yearStart = new Date(adjustedDate.getFullYear(), 0, 1)
  const weekNum = Math.ceil(((adjustedDate.getTime() - yearStart.getTime()) / 86400000 + 1) / 7)
  return `W${weekNum}`
}

const weeklyWarehouseData: Record<string, { dream: number; tumin: number }> = {}
ordersData?.forEach(order => {
  const week = getWeekNumber(order.order_date)
  if (!weeklyWarehouseData[week]) {
    weeklyWarehouseData[week] = { dream: 0, tumin: 0 }
  }
  if (order.warehouse === '드림산업') {
    weeklyWarehouseData[week].dream++
  } else if (order.warehouse === '투민글로벌') {
    weeklyWarehouseData[week].tumin++
  }
})

const weeklyData = Object.entries(weeklyWarehouseData)
  .map(([week, data]) => ({
    week,
    dream: data.dream,
    tumin: data.tumin,
    total: data.dream + data.tumin
  }))
  .sort((a, b) => a.week.localeCompare(b.week))

