// 주차별 집계 (목요일~수요일 기준)
const getWeekNumber = (dateStr: string) => {
  const date = new Date(dateStr + 'T00:00:00')
  const day = date.getDay() // 0=일요일, 1=월요일, ..., 6=토요일

  // 목요일 기준으로 조정 (목요일이 속한 주의 시작일을 구함)
  const thursday = new Date(date)
  const daysSinceThursday = (day + 3) % 7 // 목요일부터의 일수
  thursday.setDate(date.getDate() - daysSinceThursday)

  // 연초부터의 일수 계산
  const yearStart = new Date(thursday.getFullYear(), 0, 1)
  const diff = thursday.getTime() - yearStart.getTime()
  const dayOfYear = Math.floor(diff / (1000 * 60 * 60 * 24))

  // 주차 계산 (1월 1일이 속한 주가 1주차)
  const weekNum = Math.ceil((dayOfYear + 1) / 7)

  return `W${weekNum}`
}

const weeklyWarehouseData: Record<string, { dream: number; tumin: number }> = {}

ordersData?.forEach(order => {
  const week = getWeekNumber(order.order_date)
  if (!weeklyWarehouseData[week]) {
    weeklyWarehouseData[week] = { dream: 0, tumin: 0 }
  }
  if (order.warehouse === '드림산업') {
    weeklyWarehouseData[week].dream++
  } else if (order.warehouse === '투민글로벌') {
    weeklyWarehouseData[week].tumin++
  }
})

const weeklyData = Object.entries(weeklyWarehouseData)
  .map(([week, data]) => ({
    week,
    dream: data.dream,
    tumin: data.tumin,
    total: data.dream + data.tumin
  }))
  .sort((a, b) => {
    // W1, W2, ... W10, W11 순서로 정렬
    const aNum = parseInt(a.week.substring(1))
    const bNum = parseInt(b.week.substring(1))
    return aNum - bNum
  })

console.log('Weekly Data:', weeklyData.length, weeklyData.slice(0, 3))

